import re, sys, requests
url='http://localhost/'
r=requests.get(url)
html=r.text
links=set()
for m in re.finditer(r'href=[\'\"](.*?)[\'\"]', html, re.I):
    href=m.group(1)
    if href.startswith('http://localhost'):
        href=href[len('http://localhost'):]
    if href.startswith('/') and not any(href.startswith(p) for p in ['/wp-admin', '/wp-includes', '/wp-content']):
        links.add(href)
for l in sorted(links):
    print(l)
